import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { Plus, X, Calendar, Tag, Landmark, Save, Trash2 } from 'lucide-react';
import ModalFeedback from '../components/ModalFeedback';
import '../styles/Proventos.css';

const Proventos = () => {
  const [lista, setLista] = useState([]);
  const [categorias, setCategorias] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [editandoId, setEditandoId] = useState(null);
  
  // Estado para o Modal de Feedback
  const [feedback, setFeedback] = useState({
    isOpen: false,
    type: 'success',
    title: '',
    message: '',
    onConfirm: null
  });

  const [form, setForm] = useState({ 
    descricao: '', 
    valor_exibicao: 'R$ 0,00', 
    categoria_nome: '', 
    data: new Date().toISOString().split('T')[0] 
  });

  useEffect(() => {
    buscarDados();
  }, []);

  // Função para facilitar a chamada do feedback
  const alertar = (type, title, message, onConfirm = null) => {
    setFeedback({ isOpen: true, type, title, message, onConfirm });
  };

  async function buscarDados() {
    setLoading(true);
    try {
      const { data: provs } = await supabase
        .from('proventos')
        .select('*')
        .order('data_recebimento', { ascending: false });
      
      const { data: cats } = await supabase
        .from('categorias')
        .select('*')
        .eq('tipo', 'provento');

      setLista(provs || []);
      setCategorias(cats || []);

      if (cats && cats.length > 0 && !form.categoria_nome) {
        setForm(prev => ({ ...prev, categoria_nome: cats[0].nome }));
      }
    } catch (error) {
      console.error("Erro ao carregar:", error);
    } finally {
      setLoading(false);
    }
  }

  const formatMoney = (v) => 
    new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(v || 0);

  const handleMascaraMoeda = (e) => {
    let valor = e.target.value.replace(/\D/g, "");
    const valorNumerico = (Number(valor) / 100).toFixed(2);
    const valorFormatado = new Intl.NumberFormat('pt-BR', {
      style: 'currency',
      currency: 'BRL',
    }).format(valorNumerico);
    setForm({ ...form, valor_exibicao: valorFormatado });
  };

  const abrirModalNovo = () => {
    setEditandoId(null);
    setForm({ 
      descricao: '', 
      valor_exibicao: 'R$ 0,00', 
      categoria_nome: categorias[0]?.nome || '', 
      data: new Date().toISOString().split('T')[0] 
    });
    setShowModal(true);
  };

  const abrirModalEditar = (item) => {
    setEditandoId(item.id);
    setForm({
      descricao: item.descricao,
      valor_exibicao: formatMoney(item.valor),
      categoria_nome: item.categoria,
      data: item.data_recebimento
    });
    setShowModal(true);
  };

  async function handleSalvar(e) {
    e.preventDefault();
    try {
      const { data: { user } } = await supabase.auth.getUser();
      const valorLimpo = Number(form.valor_exibicao.replace(/[^\d,]/g, '').replace(',', '.'));

      const dadosProvento = {
        user_id: user.id,
        descricao: form.descricao,
        valor: valorLimpo,
        categoria: form.categoria_nome,
        data_recebimento: form.data
      };

      let error;
      if (editandoId) {
        const { error: err } = await supabase.from('proventos').update(dadosProvento).eq('id', editandoId);
        error = err;
      } else {
        const { error: err } = await supabase.from('proventos').insert([dadosProvento]);
        error = err;
      }

      if (error) throw error;
      
      setShowModal(false);
      buscarDados();
      alertar('success', 'Sucesso!', 'Seu provento foi salvo corretamente.');
    } catch (error) {
      // Aqui tratamos o erro de RLS que você recebeu na imagem
      alertar('error', 'Erro ao salvar', error.message.includes('row-level security') 
        ? 'Você não tem permissão para salvar. Verifique as políticas RLS no Supabase.' 
        : error.message);
    }
  }

  const confirmarExclusao = () => {
    alertar('error', 'Excluir Registro?', 'Esta ação não pode ser desfeita. Deseja continuar?', async () => {
      const { error } = await supabase.from('proventos').delete().eq('id', editandoId);
      if (!error) {
        setShowModal(false);
        setFeedback({ ...feedback, isOpen: false });
        buscarDados();
      } else {
        alertar('error', 'Erro ao excluir', error.message);
      }
    });
  };

  return (
    <>
      <div className="proventos-premium-wrapper">
        {/* ... (Header e Sumário permanecem iguais) ... */}
        <div className="prov-top-layout">
          <header className="prov-panel prov-header-area">
            <div className="prov-title-area">
              <h1>Proventos</h1>
              <p>Gerenciamento de Entradas</p>
            </div>
          </header>
          <div className="prov-panel prov-summary-card">
            <span className="summary-label">Total Recebido</span>
            <h2 className="summary-value">
              {formatMoney(lista.reduce((acc, cur) => acc + parseFloat(cur.valor || 0), 0))}
            </h2>
          </div>
        </div>

        <main className="prov-panel" style={{padding: 0, overflow: 'hidden'}}>
          <div style={{padding: '25px 30px', borderBottom: '1px solid #f1f5f9'}}>
            <h3 style={{margin: 0, fontWeight: 800, color: '#475569'}}>Movimentações</h3>
          </div>

          <div className="prov-list">
            {loading ? (
              <div style={{padding: '40px', textAlign: 'center'}}>Carregando...</div>
            ) : lista.map(item => (
              <div key={item.id} className="prov-item-row" onClick={() => abrirModalEditar(item)}>
                <div className="prov-left-content">
                  <div className="prov-icon-box"><Landmark size={20} /></div>
                  <div className="prov-details">
                    <span className="prov-desc">{item.descricao}</span>
                    <div className="prov-meta">
                      <span className="meta-tag"><Calendar size={12} /> {new Date(item.data_recebimento).toLocaleDateString('pt-BR', {timeZone: 'UTC'})}</span>
                      <span className="meta-tag"><Tag size={12} /> {item.categoria}</span>
                    </div>
                  </div>
                </div>
                <span className="prov-value">{formatMoney(item.valor)}</span>
              </div>
            ))}
          </div>
        </main>

        {showModal && (
          <div className="modal-overlay" onClick={() => setShowModal(false)}>
            <div className="prov-modal" onClick={e => e.stopPropagation()}>
              <div className="modal-header-flex">
                <h2 style={{margin: 0, fontWeight: 900}}>Detalhes</h2>
                <button onClick={() => setShowModal(false)} className="close-modal-btn"><X size={20} /></button>
              </div>
              
              <form onSubmit={handleSalvar}>
                <div className="form-group">
                  <label>O QUE FOI RECEBIDO?</label>
                  <input type="text" required value={form.descricao} onChange={e => setForm({...form, descricao: e.target.value})} placeholder="Ex: Salário" />
                </div>

                <div className="form-row">
                  <div className="form-group">
                    <label>VALOR</label>
                    <input type="text" required value={form.valor_exibicao} onChange={handleMascaraMoeda} />
                  </div>
                  <div className="form-group">
                    <label>DATA</label>
                    <input type="date" required value={form.data} onChange={e => setForm({...form, data: e.target.value})} />
                  </div>
                </div>

                <div className="form-group">
                  <label>CATEGORIA</label>
                  <select value={form.categoria_nome} onChange={e => setForm({...form, categoria_nome: e.target.value})} required>
                    {categorias.map(cat => <option key={cat.id} value={cat.nome}>{cat.nome}</option>)}
                  </select>
                </div>

                <button type="submit" className="btn-save-prov">
                   <Save size={18} /> Salvar Alterações
                </button>

                {editandoId && (
                  <button type="button" onClick={confirmarExclusao} className="btn-delete-prov">
                    <Trash2 size={18} /> Excluir Lançamento
                  </button>
                )}
              </form>
            </div>
          </div>
        )}
      </div>

      {/* COMPONENTE DE FEEDBACK */}
      <ModalFeedback 
        isOpen={feedback.isOpen}
        type={feedback.type}
        title={feedback.title}
        message={feedback.message}
        onClose={() => setFeedback({ ...feedback, isOpen: false })}
        onConfirm={feedback.onConfirm}
      />

      <button className="prov-fab" onClick={abrirModalNovo}><Plus size={30} /></button>
    </>
  );
};

export default Proventos;
